    std::uint64_t aNonceWordF = TwistMix64::DiffuseC(pNonce * 0xCE706ACAC33E5797ULL + 0xBAF9F07B252E43EFULL);
    std::uint64_t aNonceWordG = TwistMix64::DiffuseC(pNonce * 0xABDAC5B09FD35327ULL + 0x9FBF64EF253761B8ULL);
    std::uint64_t aNonceWordH = TwistMix64::DiffuseB(pNonce * 0xD090126A447C1D7FULL + 0xB86B7221B4854AA1ULL);
    std::uint64_t aNonceWordI = TwistMix64::DiffuseC(pNonce * 0x917139FB6AC803FDULL + 0xE40A8F99DA2FB7CDULL);
    std::uint64_t aNonceWordJ = TwistMix64::DiffuseB(pNonce * 0xEE01ECBE86AC3A5DULL + 0xA3F3925F97602142ULL);
