    std::uint64_t aNonceWordM = TwistMix64::DiffuseB(pNonce * 0x8C3E69C2106CF8DFULL + 0xC7AA6E2B52F48335ULL);
    std::uint64_t aNonceWordN = TwistMix64::DiffuseB(pNonce * 0xC0290D11BD1FB2A7ULL + 0xDC647A27EB8DBC97ULL);
