            //
            aScatter = (RotL64(aPrevious, 27U) ^ RotL64(aCarry, 57U)) ^ (RotL64(aCross, 13U) + RotL64(aIngress, 44U));
            aScatter = TwistMix64::DiffuseC(((aScatter ^ aDomainWordScatter) ^ aNonceWordL));
            //
            aOrbiterC = ((aWandererG + RotL64(aCross, 41U)) + RotL64(aCarry, 27U)) + 17711946802293254150U;
            aOrbiterG = (((aWandererE + RotL64(aScatter, 56U)) + 16652362590489569378U) + aOrbiterAssignSaltF[(((31U - aIndex) + 17U)) & S_SALT1]) + aNonceWordH;
            aOrbiterE = ((aWandererI + RotL64(aPrevious, 53U)) + 6972810344198183097U) + aNonceWordI;
