            //
            aOrbiterE = (aOrbiterE + aOrbiterA) + 7700902083270424194U;
            aOrbiterK = (aOrbiterK ^ aOrbiterE) ^ 1888001433557140271U;
            aOrbiterK = RotL64((aOrbiterK * 8975562955027025349U), 13U);
            //
            aOrbiterI = ((aOrbiterI + aOrbiterK) + 14996753906788986929U) + aNonceWordF;
            aOrbiterC = (aOrbiterC ^ aOrbiterI) ^ 939004845422123765U;
            aOrbiterC = RotL64((aOrbiterC * 2507090308972292313U), 29U);
            //
            aOrbiterF = (aOrbiterF + aOrbiterH) + 11922230289291941807U;
            aOrbiterD = ((aOrbiterD ^ aOrbiterF) ^ 15681187459741147199U) ^ aOrbiterUpdateSaltD[((aIndex + 6U)) & S_SALT1];
            aOrbiterD = RotL64((aOrbiterD * 10124947739653819101U), 53U);
            //
            aOrbiterH = (aOrbiterH + aOrbiterC) + 9119043713532718155U;
            aOrbiterB = ((aOrbiterB ^ aOrbiterH) ^ 8327697433992362166U) ^ aNonceWordE;
            aOrbiterB = RotL64((aOrbiterB * 11157657162184304567U), 21U);
            //
            aOrbiterD = (aOrbiterD + aOrbiterB) + 13630755116592440359U;
            aOrbiterJ = ((aOrbiterJ ^ aOrbiterD) ^ 771252613886022889U) ^ aNonceWordO;
            aOrbiterJ = RotL64((aOrbiterJ * 2958918915223536519U), 23U);
            //
            aOrbiterG = (aOrbiterG + aOrbiterD) + 8524239721467527770U;
            aOrbiterA = (aOrbiterA ^ aOrbiterG) ^ 17732617735422435572U;
            aOrbiterA = RotL64((aOrbiterA * 13992947983987668631U), 27U);
            //
            aOrbiterB = (aOrbiterB + aOrbiterE) + 5265753270696005619U;
