            //
            aOrbiterJ = (aOrbiterJ + aOrbiterI) + 12909993509014176457U;
            aOrbiterH = (aOrbiterH ^ aOrbiterJ) ^ 10113568710432654194U;
            aOrbiterH = RotL64((aOrbiterH * 6857806395910432831U), 11U);
            //
            aOrbiterK = (aOrbiterK + aOrbiterF) + 14818978163348513071U;
            aOrbiterG = (((aOrbiterG ^ aOrbiterK) ^ 17843349910031998923U) ^ aOrbiterUpdateSaltE[(((31U - aIndex) + 27U)) & S_SALT1]) ^ aNonceWordG;
            aOrbiterG = RotL64((aOrbiterG * 13608449524810499593U), 39U);
            //
            aOrbiterA = (aOrbiterA + aOrbiterJ) + 12589077818524017161U;
