            aIngress = aIngress + (RotL64(aOrbiterJ, 21U) ^ aOrbiterI);
            aIngress = aIngress + (RotL64(aOrbiterG, 37U) ^ aOrbiterF);
            aIngress = aIngress + RotL64(aOrbiterC, 58U);
            aIngress = TwistMix64::DiffuseB((aIngress + aScatter));
            //
            aWandererD = aWandererD ^ ((RotL64(aScatter, 3U) + aOrbiterB) + RotL64(aOrbiterK, 50U));
            aWandererA = aWandererA + ((RotL64(aIngress, 27U) + aOrbiterF) + RotL64(aOrbiterG, 47U));
            aWandererC = aWandererC ^ ((RotL64(aPrevious, 43U) + RotL64(aOrbiterC, 27U)) + aOrbiterD);
            aWandererB = aWandererB + ((RotL64(aCross, 60U) + aOrbiterF) + RotL64(aOrbiterI, 19U));
